// フィットネスアプリのイベント設計
const eventSchema = {
  // ワークアウト開始イベント
  workoutStart: {
    // イベント名をスネークケースで入力してください
    eventName: '',
    params: {
      // ワークアウトの種類（例: 'running', 'yoga'）
      workout_type: '',
      // 目標時間（分）
      target_duration_min: 0
    }
  },

  // ワークアウト完了イベント
  workoutComplete: {
    eventName: '',
    params: {
      // ワークアウトの種類
      workout_type: '',
      // 実際の時間（分）
      actual_duration_min: 0,
      // 消費カロリー
      calories_burned: 0
    }
  },

  // プレミアムプラン購入イベント（Googleの推奨イベント名を使うこと）
  premiumPurchase: {
    eventName: '',  // 'purchase' を使う
    params: {
      transaction_id: '',
      value: 0,
      currency: 'JPY'
    }
  }
};

// 確認出力（変更不要）
Object.entries(eventSchema).forEach(([key, schema]) => {
  console.log(`[${key}]`);
  console.log('  イベント名:', schema.eventName);
  console.log('  パラメータ:', Object.keys(schema.params).join(', '));
});

